```go
package main

import (
	"fmt"
	"log"
	"net/http"
	"io/ioutil"
	"os"
)

func handler(w http.ResponseWriter, r *http.Request) {
	// Print the request method
	fmt.Println("Request Method:", r.Method)

	// Print the request URL
	fmt.Println("Request URL:", r.URL)

	// Print the request headers
	fmt.Println("Request Headers:")
	for k, v := range r.Header {
		fmt.Println("  ", k, ":", v)
	}

	// Print the request body
	body, err := ioutil.ReadAll(r.Body)
	if err != nil {
		log.Println("Error reading request body:", err)
		return
	}
	fmt.Println("Request Body:", string(body))

	// Write a response
	w.WriteHeader(http.StatusOK)
	fmt.Fprintf(w, "Request processed successfully")
}

func main() {
	// Set up the HTTP server
	http.HandleFunc("/", handler)
	fmt.Println("Server is listening on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

### Explanation:
- **Handler Function**: The `handler` function is called for every incoming request.
- **Request Method and URL**: It prints the method and URL of the request.
- **Request Headers**: It iterates over and prints all the headers.
- **Request Body**: It reads the request body and prints it as a string.
- **HTTP Server**: The `main` function sets up an HTTP server that listens on port `8080`. The `http.ListenAndServe` function starts the server, and it will call the `handler` function for each incoming request.

You can run this program and test it by making HTTP requests to `http://localhost:8080`.

